#include <bits/stdc++.h>
using namespace std;
struct Number{
    int len,val[520];
}ans,base;
Number times(Number x,Number y){
    Number r;
    r.len=min(x.len+y.len-1,500);
    memset(r.val,0,sizeof(r.val));
   	for(int i=1;i<=x.len;i++)
	   	for(int j=1;j<=y.len;j++)
	   		if(i+j-1<=500){
				r.val[i+j-1]+=x.val[i]*y.val[j];
				r.val[i+j]+=r.val[i+j-1]/10;
				r.val[i+j-1]%=10;
			}
	while(r.val[r.len+1] && r.len<500)
		r.len++,r.val[r.len+1]+=r.val[r.len]/10,r.val[r.len]%=10;
	return r;
}
int p;
int main(){
    scanf("%d",&p);
    printf("%d",(int)(log10(2)*p+1));
    ans.len=1;
    memset(ans.val,0,sizeof(ans.val));
    ans.val[1]=1;
    base.len=1;
    memset(base.val,0,sizeof(base.val));
    base.val[1]=2;
    while(p){
        if(p&1)
            ans=times(ans,base);
        base=times(base,base),p/=2;
    }
    ans.val[1]--;
    for(int i=500;i;i--){
    	if(i%50==0)
    		printf("\n");
    	printf("%d",ans.val[i]);
    }
    return 0;
}
